where.if:
AND EXISTS (
    SELECT 1
    FROM EMP_ROLE ER
    WHERE ER.EMP_NO = E.EMP_NO
      AND ER.ROLE_CD = #{params.deptRoleCd}
)

AND EXISTS (
    SELECT 1
    FROM EMP_ROLE ER
    WHERE ER.EMP_NO = E.EMP_NO
      AND ER.ROLE_CD = #{params.posRoleCd}
)

AND EXISTS (
    SELECT 1
    FROM EMP_ROLE ER
    WHERE ER.EMP_NO = E.EMP_NO
      AND ER.ROLE_CD = #{params.roleCd}
)

mapper.select:
SELECT * FROM (
    SELECT a_inner.*, ROWNUM rnum FROM (
        SELECT

        FROM EMP E
        LEFT JOIN DEPT D ON E.DEPT_CD = D.DEPT_CD
        LEFT JOIN POSITION_MST P ON E.POS_CD = P.POS_CD

        ORDER BY E.EMP_NO DESC
    ) a_inner
    WHERE ROWNUM <= #{paging.page} * #{paging.recordSize}
)
WHERE rnum > (#{paging.page} - 1) * #{paging.recordSize}

SELECT COUNT(*)
FROM ROLE_MST
WHERE ROLE_CD = #{roleCd}

SELECT COUNT(*)
FROM EMP_ROLE
WHERE ROLE_CD = #{roleCd}

SELECT COUNT(*)
FROM MENU_ROLE
WHERE ROLE_CD = #{roleCd}

SELECT COUNT(*)
FROM ROLE_HIERARCHY
WHERE PARENT_ROLE_CD = #{roleCd}
   OR CHILD_ROLE_CD = #{roleCd}
